import * as api from '../api'

export const signup = (authData, history) => async (dispatch) => {
    try{
        const { data } = await api.signUp(authData)
        dispatch({ type: 'AUTH', data}) 
    } catch (error) {
        
    }
}

export const login = (authData, history) => {}
